import React, { useState } from "react";
import logo from "./assets/logo.png";
import "../Componants/Nav.css";
import { Link } from "react-router-dom";
 

export default function Nav() {
  const [showmenu, setmenu] = useState(false);

  return (
    <div>
      <nav className="navbar">
        <img src={logo} alt="Logo" id="logo" />

        

        <span className="desktopmenu">
         {/* Book Now Button */}
        <div className="book-btn">
        <button className="book-now-btn">
              <Link to="/Book" className="book-now-link">
                Book Now
              </Link>
            </button>
          </div>
          
          {/* Navigation Links */}
          <Link
            activeClass="active"
            to="intro"
            spy={true}
            smooth={true}
            offset={-100}
            duration={500}
            className="desktopmenuListitem"
          >
            Home
          </Link>
          <Link
            activeClass="active"
            to="portfolio"
            spy={true}
            smooth={true}
            offset={-100}
            duration={500}
            className="desktopmenuListitem"
          >
            Contact Us
          </Link>
          <Link
            activeClass="active"
            to="aboutus"
            spy={true}
            smooth={true}
            offset={-100}
            duration={500}
            className="desktopmenuListitem"
          >
            Blog
          </Link>
          <Link
            activeClass="active"
            to="login"
            spy={true}
            smooth={true}
            offset={-100}
            duration={500}
            className="desktopmenuListitem"
          >
            
            Login
          </Link>
        </span>

        <div className="navMenu" style={{ display: showmenu ? "flex" : "none" }}>
          <Link
            activeClass="active"
            to="intro"
            spy={true}
            smooth={true}
            offset={-100}
            duration={500}
            className="desktopmenuListitem"
            onClick={() => setmenu(false)}
          >
            Home
          </Link>
          <Link
            activeClass="active"
            to="services"
            spy={true}
            smooth={true}
            offset={-100}
            duration={500}
            className="desktopmenuListitem"
            onClick={() => setmenu(false)}
          >
            Services
          </Link>
          <Link
            activeClass="active"
            to="portfolio"
            spy={true}
            smooth={true}
            offset={-100}
            duration={500}
            className="desktopmenuListitem"
            onClick={() => setmenu(false)}
          >
            Portfolio
          </Link>
          <Link
            activeClass="active"
            to="aboutus"
            spy={true}
            smooth={true}
            offset={-100}
            duration={500}
            className="desktopmenuListitem"
            onClick={() => setmenu(false)}
          >
            About
          </Link>
        </div>
      </nav>
    </div>
  );
}
